#include <stdio.h>
int max(int a, int b) { return (a > b) ? a : b; }
int longestBitonicSequence(int arr[], int n) {
    int LIS[n], LDS[n];
    for (int i = 0; i < n; i++) {
        LIS[i] = 1;
        LDS[i] = 1;
    }
    for (int i = 1; i < n; i++) {
        for (int j = 0; j < i; j++) {
            if (arr[i] > arr[j] && LIS[i] < LIS[j] + 1) {
                LIS[i] = LIS[j] + 1;
            }
        }
    }
    for (int i = n - 2; i >= 0; i--) {
        for (int j = n - 1; j > i; j--) {
            if (arr[i] > arr[j] && LDS[i] < LDS[j] + 1) {
                LDS[i] = LDS[j] + 1;
            }
        }
    }
    int maxLen = 0;
    for (int i = 0; i < n; i++) {
        maxLen = max(maxLen, LIS[i] + LDS[i] - 1);
    }
    return maxLen;
}
int main() {
    int arr[] = {5, 1, 4, 2, 3, 6, 8, 7};
    int n = sizeof(arr) / sizeof(arr[0]);
    printf("The length of the Longest Bitonic Sequence is: %d\n", longestBitonicSequence(arr, n));
    return 0;
}

